using ChurnPredictor;
using Microsoft.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train & evaluate the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

var allData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}  " +
                  $"F1: {metrics.F1Score:F4}  " +
                  $"Accuracy: {metrics.Accuracy:F4}");

// Save model for PredictionEnginePool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

// Register thread-safe prediction engine pool
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict");

app.MapPost("/predict", (
    Microsoft.Extensions.ML.PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerPredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.Churned,
        result.Probability
    });
});

app.Run();

public sealed record CustomerPredictRequest(
    float Age, float Income, string Region, float PurchaseHistory);

